import{_ as i,o as a,c as e,ag as t}from"./chunks/framework.BDReElpY.js";const c=JSON.parse('{"title":"Tensor and Mask Types","description":"","frontmatter":{},"headers":[],"relativePath":"guide/simd/tensor-mask.md","filePath":"guide/simd/tensor-mask.md"}'),n={name:"guide/simd/tensor-mask.md"};function l(h,s,r,o,p,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="tensor-and-mask-types" tabindex="-1">Tensor and Mask Types <a class="header-anchor" href="#tensor-and-mask-types" aria-label="Permalink to &quot;Tensor and Mask Types&quot;">​</a></h1><p><code>Tensor</code> and <code>Mask</code> are the types that connect user-facing graph code to the SIR and SIMD backends.</p><p>The important distinction is this:</p><ul><li>small static tensors line up closely with array and vector lowering</li><li>dynamic tensors are owning fat-pointer values with their own ABI and drop behavior</li><li>masks are the boolean side of that model and have both static and dynamic forms</li></ul><h2 id="layout-overview" tabindex="-1">Layout overview <a class="header-anchor" href="#layout-overview" aria-label="Permalink to &quot;Layout overview&quot;">​</a></h2><p>Current compiler and SIR shape contracts are centered around these mappings:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tensor&lt;f32, 4&gt;  -&gt; Ty::Array(f32, 4)  -&gt; &lt;4 x float&gt;</span></span>
<span class="line"><span>Tensor&lt;f32, 32&gt; -&gt; Ty::Array(f32, 32) -&gt; [32 x float]</span></span>
<span class="line"><span>Tensor&lt;f32&gt;     -&gt; Ty::DynTensor(f32) -&gt; %VexDynTensor { ptr, i64 }</span></span>
<span class="line"><span>Mask&lt;4&gt;         -&gt; Ty::Mask(4)        -&gt; &lt;4 x i1&gt;</span></span>
<span class="line"><span>Mask            -&gt; Ty::DynMask        -&gt; %VexDynMask { ptr, i64 }</span></span></code></pre></div><p>That split matters because static and dynamic tensors do not behave like a single interchangeable runtime object.</p><h2 id="static-tensor-t-n" tabindex="-1">Static <code>Tensor&lt;T, N&gt;</code> <a class="header-anchor" href="#static-tensor-t-n" aria-label="Permalink to &quot;Static \`Tensor&lt;T, N&gt;\`&quot;">​</a></h2><p>Static tensors are compile-time sized.</p><p>In practice, the compiler lowers them through array machinery first:</p><ul><li>if the total size is at most 64 bytes, they can become LLVM vector values</li><li>if the total size is larger than 64 bytes, they stay as memory arrays</li></ul><p>So <code>Tensor&lt;f32, 4&gt;</code> and <code>Tensor&lt;f32, 8&gt;</code> are good mental models for inline SIMD, while larger static tensors should be thought of as shaped arrays that may still be optimized later.</p><p>Example:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Tensor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, 4&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Tensor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, 4&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> c </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b</span></span></code></pre></div><h2 id="dynamic-tensor-t" tabindex="-1">Dynamic <code>Tensor&lt;T&gt;</code> <a class="header-anchor" href="#dynamic-tensor-t" aria-label="Permalink to &quot;Dynamic \`Tensor&lt;T&gt;\`&quot;">​</a></h2><p>Dynamic tensors lower to an owning <code>%VexDynTensor { ptr, i64 }</code> layout.</p><p>The important property is ownership: the data buffer is heap-managed and participates in drop logic. That is why the compiler explicitly guards against creating a fake dynamic tensor by merely aliasing a stack vector as <code>{ ptr, i64 }</code>.</p><p>This also means that conversions into <code>Tensor&lt;T&gt;</code> are not all equivalent in cost or semantics.</p><h3 id="practical-consequences" tabindex="-1">Practical consequences <a class="header-anchor" href="#practical-consequences" aria-label="Permalink to &quot;Practical consequences&quot;">​</a></h3><ul><li><code>Tensor&lt;T&gt;</code> is an owning runtime value, not just a borrowed view</li><li><code>Span&lt;T&gt; -&gt; Tensor&lt;T&gt;</code> is a copy into owned tensor storage</li><li>static vector values are not documented as a zero-cost reinterpretation into <code>Tensor&lt;T&gt;</code></li></ul><p>Concrete tensor code is the safest thing to document today:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> relu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Tensor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Tensor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="mask-n-and-mask" tabindex="-1"><code>Mask&lt;N&gt;</code> and <code>Mask</code> <a class="header-anchor" href="#mask-n-and-mask" aria-label="Permalink to &quot;\`Mask&lt;N&gt;\` and \`Mask\`&quot;">​</a></h2><p>Masks represent boolean results from comparisons and masking operations.</p><p>Static masks use vector-friendly layouts during comparison codegen, while dynamic masks use a <code>%VexDynMask { ptr, i64 }</code> fat-pointer layout.</p><p>Examples of the mask surface that is grounded in current lowering and backend code include:</p><ul><li><code>any()</code></li><li><code>all()</code></li><li><code>countBits()</code> or <code>popcount()</code></li><li><code>firstSet()</code></li><li><code>select(true_value, false_value)</code></li></ul><p>Example:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mask </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mask</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">any</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> first </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mask</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">firstSet</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    $</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">println(first)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="where-static-tensors-stop-being-just-simd" tabindex="-1">Where static tensors stop being &quot;just SIMD&quot; <a class="header-anchor" href="#where-static-tensors-stop-being-just-simd" aria-label="Permalink to &quot;Where static tensors stop being &quot;just SIMD&quot;&quot;">​</a></h2><p>The old simplified story was &quot;tensor equals register vector&quot;. That is too broad.</p><p>The more accurate model is:</p><ul><li>small static tensors can map directly to vector IR</li><li>larger static tensors are shaped arrays</li><li>dynamic tensors are owning fat-pointer values</li><li>backend routing depends on shape, operation family, and the selected pipeline</li></ul><h2 id="current-limitations-worth-knowing" tabindex="-1">Current limitations worth knowing <a class="header-anchor" href="#current-limitations-worth-knowing" aria-label="Permalink to &quot;Current limitations worth knowing&quot;">​</a></h2><p>These constraints are real and should be assumed until the compiler surface is broadened further:</p><ul><li>generic arithmetic over <code>Tensor&lt;T&gt;</code> is not a safe thing to document as generally available</li><li>not every <code>Span&lt;T&gt;</code> to <code>Tensor&lt;T&gt;</code> boundary behaves like a trivial view conversion</li><li>tensor routing is strongest in concrete, graph-oriented code such as <code>Tensor&lt;f32&gt;</code> workloads</li></ul><h2 id="when-to-use-what" tabindex="-1">When to use what <a class="header-anchor" href="#when-to-use-what" aria-label="Permalink to &quot;When to use what&quot;">​</a></h2><p>Use <code>Tensor&lt;T, N&gt;</code> when:</p><ul><li>the size is fixed at compile time</li><li>you want shaped numeric data</li><li>the hot path benefits from static lowering</li></ul><p>Use <code>Tensor&lt;T&gt;</code> when:</p><ul><li>the shape is runtime-sized</li><li>the code is naturally graph or ML oriented</li><li>ownership of the tensor buffer is acceptable</li></ul><p>Use <code>Mask&lt;N&gt;</code> or <code>Mask</code> when:</p><ul><li>you are working with comparison results</li><li>you need selection, filtering, or bit-count style mask queries</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./index">SIMD and Auto-Vectorization</a></li><li><a href="./sir-pipeline">SIR Optimization Pipeline</a></li><li><a href="/docs/guide/gpu">GPU Programming</a></li></ul>`,46)])])}const g=i(n,[["render",l]]);export{c as __pageData,g as default};
